document.addEventListener("DOMContentLoaded", () => {
  const triggers = document.querySelectorAll('[data-pressed="disappear"]');
  const overlay = document.querySelector(".canvas_overlay_content");

  if (!triggers.length || !overlay) return;

  triggers.forEach((el) => {
    el.addEventListener("click", () => {
      overlay.style.transition =
        "opacity 0.7s cubic-bezier(0.22, 1, 0.36, 1), transform 0.7s cubic-bezier(0.22, 1, 0.36, 1)";
      overlay.style.willChange = "opacity, transform";
      overlay.style.pointerEvents = "none";

      requestAnimationFrame(() => {
        overlay.style.opacity = "0";
        overlay.style.transform = "translateY(-24px)";
      });

      setTimeout(() => {
        overlay.style.display = "none";
      }, 700);
    });
  });
});


document.addEventListener("DOMContentLoaded", () => {

  let headings = document.querySelectorAll('[data-split="heading"]')
  headings.forEach(heading => {
    SplitText.create(heading, {
      type: "lines",
      autoSplit: true,
      mask: "lines",
      onSplit(instance) {
        return gsap.from(instance.lines, {
          duration: 0.8, 
          yPercent: 110,
          stagger: 0.1,
          ease:"expo.out",
          scrollTrigger: {
            trigger: heading,
            start: 'top 80%',
            once: true,
          }
        });
      }
    });    
  });
});

document.addEventListener("DOMContentLoaded", () => {
  if (typeof gsap === "undefined" || typeof InertiaPlugin === "undefined") {
    return;
  }

  gsap.registerPlugin(InertiaPlugin);

  const viewport = document.querySelector(".canvas_viewport");
  const stage = document.querySelector(".canvas_stage");
  const source = document.querySelector(".project_cards_source");
  const dragButton = document.getElementById("drag_active");

  if (!viewport || !stage || !source) return;

  const sourceCards = Array.from(source.querySelectorAll(".project_card"));
  if (!sourceCards.length) return;

  const GAP_X = 112;
  const GAP_Y = 112;
  const MAX_COLS = 8;

  const MIN_SCALE = 0.5;
  const MAX_SCALE = 2.5;
  const ZOOM_INTENSITY = 0.0015;
  const DRAG_THRESHOLD = 4;

  const state = {
    x: 0,
    y: 0,
    scale: 1,
    isDragging: false,
    hasMoved: false,
    startX: 0,
    startY: 0
  };

  let isDragEnabled = false;
  let inertiaTween = null;
  let lastTileSignature = "";
  let tileWidth = 0;
  let tileHeight = 0;
  let cardWidth = 0;
  let cardHeight = 0;
  let cols = 0;
  let rows = 0;
  let gridWidth = 0;
  let gridHeight = 0;

  function clamp(value, min, max) {
    return Math.min(max, Math.max(min, value));
  }

  function getTileCards(cards) {
    return cards;
  }

  function render() {
    stage.style.transform = `translate3d(${state.x}px, ${state.y}px, 0) scale(${state.scale})`;
  }

  function getCardSize() {
    const rem = parseFloat(getComputedStyle(document.documentElement).fontSize);
    return {
      width: 20 * rem,
      height: 26 * rem
    };
  }

  function computeLayoutMetrics() {
    const size = getCardSize();
    cardWidth = size.width;
    cardHeight = size.height;

    cols = Math.min(sourceCards.length, MAX_COLS);
    rows = Math.ceil(sourceCards.length / cols);

    gridWidth = cols * cardWidth + (cols - 1) * GAP_X;
    gridHeight = rows * cardHeight + (rows - 1) * GAP_Y;

    tileWidth = gridWidth + GAP_X;
    tileHeight = gridHeight + GAP_Y;
  }

  function centerView(resetScale = true) {
    if (resetScale) state.scale = 1;

    const vw = viewport.clientWidth;
    const vh = viewport.clientHeight;

    state.x = (vw - tileWidth * state.scale) / 2;
    state.y = (vh - tileHeight * state.scale) / 2;

    ensureTiles();
    render();
  }

  function wrapPosition() {
    while (state.x > tileWidth / 2) state.x -= tileWidth;
    while (state.x < -tileWidth / 2) state.x += tileWidth;
    while (state.y > tileHeight / 2) state.y -= tileHeight;
    while (state.y < -tileHeight / 2) state.y += tileHeight;
  }

  function getTileRange() {
    const vw = viewport.clientWidth;
    const vh = viewport.clientHeight;

    const visibleWidth = vw / state.scale;
    const visibleHeight = vh / state.scale;

    const tilesX = Math.ceil(visibleWidth / tileWidth) + 2;
    const tilesY = Math.ceil(visibleHeight / tileHeight) + 2;

    const halfX = Math.ceil(tilesX / 2);
    const halfY = Math.ceil(tilesY / 2);

    return {
      minCol: -halfX,
      maxCol: halfX,
      minRow: -halfY,
      maxRow: halfY
    };
  }

  function buildWorlds() {
    stage.innerHTML = "";

    const range = getTileRange();

    for (let row = range.minRow; row <= range.maxRow; row++) {
      for (let col = range.minCol; col <= range.maxCol; col++) {
        const world = document.createElement("div");
        world.className = "canvas_world";

        const tileShiftX = row % 2 !== 0 ? (cardWidth + GAP_X) / 2 : 0;
        const tileShiftY = 0;

        world.style.left = `${col * tileWidth + tileShiftX}px`;
        world.style.top = `${row * tileHeight + tileShiftY}px`;
        world.style.width = `${tileWidth}px`;
        world.style.height = `${tileHeight}px`;

        const orderedCards = getTileCards(sourceCards);

        orderedCards.forEach((sourceCard, index) => {
          const card = sourceCard.cloneNode(true);
          const gridRow = Math.floor(index / cols);
          const gridCol = index % cols;

          const itemsInRow =
            gridRow === Math.floor((orderedCards.length - 1) / cols)
              ? orderedCards.length % cols || cols
              : cols;

          const rowWidth = itemsInRow * cardWidth + (itemsInRow - 1) * GAP_X;
          const rowOffsetX = (gridWidth - rowWidth) / 2;

          const x = rowOffsetX + gridCol * (cardWidth + GAP_X);
          const y = gridRow * (cardHeight + GAP_Y);

          card.style.position = "absolute";
          card.style.left = `${x}px`;
          card.style.top = `${y}px`;

          card.addEventListener("click", (e) => {
            if (state.hasMoved) e.preventDefault();
          });

          world.appendChild(card);
        });

        stage.appendChild(world);
      }
    }

    lastTileSignature = `${range.minCol},${range.maxCol},${range.minRow},${range.maxRow},${tileWidth},${tileHeight}`;
  }

  function ensureTiles() {
    const range = getTileRange();
    const signature = `${range.minCol},${range.maxCol},${range.minRow},${range.maxRow},${tileWidth},${tileHeight}`;

    if (signature !== lastTileSignature) {
      buildWorlds();
    }
  }

  function syncScene() {
    wrapPosition();
    ensureTiles();
    render();
  }

  function getAllRenderedCards() {
    return stage.querySelectorAll(".project_card");
  }

  function animateCardsByVelocity(vx, vy) {
    const cards = getAllRenderedCards();
    const offsetX = clamp(vx * 0.12, -18, 18);
    const offsetY = clamp(vy * 0.12, -18, 18);
    const speed = Math.abs(vx) + Math.abs(vy);
    const blur = clamp(speed * 0.015, 0, 3);

    cards.forEach((card, index) => {
      const depth = 0.88 + (index % 5) * 0.04;

      gsap.to(card, {
        x: offsetX * depth,
        y: offsetY * depth,
        filter: `blur(${blur}px)`,
        duration: 0.22,
        ease: "power2.out",
        overwrite: true
      });
    });
  }

  function resetCardsReaction() {
    const cards = getAllRenderedCards();

    cards.forEach((card) => {
      gsap.to(card, {
        x: 0,
        y: 0,
        filter: "blur(0px)",
        duration: 0.7,
        ease: "power3.out",
        overwrite: true
      });
    });
  }

  function killInertia() {
    if (inertiaTween) {
      inertiaTween.kill();
      inertiaTween = null;
    }
  }

  function startInertia() {
    const vx = InertiaPlugin.getVelocity(state, "x");
    const vy = InertiaPlugin.getVelocity(state, "y");

    inertiaTween = gsap.to(state, {
      inertia: {
        x: { velocity: vx, resistance: 1400 },
        y: { velocity: vy, resistance: 1400 }
      },
      duration: 2.5,
      ease: "power3.out",
      onUpdate: () => {
        syncScene();

        const currentVX = InertiaPlugin.getVelocity(state, "x");
        const currentVY = InertiaPlugin.getVelocity(state, "y");
        animateCardsByVelocity(currentVX, currentVY);
      },
      onComplete: () => {
        inertiaTween = null;
        resetCardsReaction();
      }
    });
  }

  function setDragEnabled(enabled) {
    isDragEnabled = enabled;

    if (dragButton) {
      dragButton.classList.toggle("is-active", isDragEnabled);
    }

    viewport.style.cursor = isDragEnabled ? "grab" : "default";

    if (!isDragEnabled) {
      killInertia();
      resetCardsReaction();
      state.isDragging = false;
    }
  }

  InertiaPlugin.track(state, "x,y");

  if (dragButton) {
    dragButton.addEventListener("click", () => {
      setDragEnabled(!isDragEnabled);
    });
  }

  viewport.addEventListener("pointerdown", (e) => {
    if (!isDragEnabled) return;

    killInertia();
    state.isDragging = true;
    state.hasMoved = false;
    state.startX = e.clientX - state.x;
    state.startY = e.clientY - state.y;
    viewport.style.cursor = "grabbing";
  });

  window.addEventListener("pointermove", (e) => {
    if (!state.isDragging || !isDragEnabled) return;

    const newX = e.clientX - state.startX;
    const newY = e.clientY - state.startY;

    const vx = newX - state.x;
    const vy = newY - state.y;

    if (Math.abs(vx) > DRAG_THRESHOLD || Math.abs(vy) > DRAG_THRESHOLD) {
      state.hasMoved = true;
    }

    state.x = newX;
    state.y = newY;

    syncScene();
    animateCardsByVelocity(vx, vy);
  });

  window.addEventListener("pointerup", () => {
    if (!state.isDragging) return;

    state.isDragging = false;
    viewport.style.cursor = isDragEnabled ? "grab" : "default";

    if (state.hasMoved && isDragEnabled) {
      startInertia();
    } else {
      resetCardsReaction();
    }
  });

  viewport.addEventListener(
    "wheel",
    (e) => {
      if (!isDragEnabled) return;

      e.preventDefault();
      killInertia();

      const newScale = Math.min(
        MAX_SCALE,
        Math.max(MIN_SCALE, state.scale - e.deltaY * ZOOM_INTENSITY)
      );

      const rect = viewport.getBoundingClientRect();
      const mouseX = e.clientX - rect.left;
      const mouseY = e.clientY - rect.top;

      const worldX = (mouseX - state.x) / state.scale;
      const worldY = (mouseY - state.y) / state.scale;

      state.x = mouseX - worldX * newScale;
      state.y = mouseY - worldY * newScale;
      state.scale = newScale;

      syncScene();
      resetCardsReaction();
    },
    { passive: false }
  );

  window.resetCanvas = function () {
    killInertia();
    resetCardsReaction();
    centerView(true);
  };

  function init() {
    computeLayoutMetrics();
    buildWorlds();
    centerView(true);
    resetCardsReaction();
    setDragEnabled(false);
  }

  window.addEventListener("load", () => {
    setTimeout(init, 80);
  });

  setTimeout(init, 180);

  window.addEventListener("resize", () => {
    killInertia();
    computeLayoutMetrics();
    lastTileSignature = "";
    centerView(false);
    resetCardsReaction();
    viewport.style.cursor = isDragEnabled ? "grab" : "default";
  });
});

document.addEventListener("DOMContentLoaded", () => {
  const triggers = document.querySelectorAll('[data-pressed="disappear"]');
  const overlay = document.querySelector(".canvas_overlay_content");

  if (!triggers.length || !overlay) return;

  triggers.forEach((el) => {
    el.addEventListener("click", () => {
      overlay.style.transition =
        "opacity 0.7s cubic-bezier(0.22, 1, 0.36, 1), transform 0.7s cubic-bezier(0.22, 1, 0.36, 1)";
      overlay.style.willChange = "opacity, transform";
      overlay.style.pointerEvents = "none";

      requestAnimationFrame(() => {
        overlay.style.opacity = "0";
        overlay.style.transform = "translateY(-24px)";
      });

      setTimeout(() => {
        overlay.style.display = "none";
      }, 700);
    });
  });
});
